import{_ as t}from"./chunks/project-settings_01.CuuUlwv5.js";import{_ as a,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Project Settings","description":"","frontmatter":{},"headers":[],"relativePath":"configuration/project-settings.md","filePath":"configuration/project-settings.md"}'),o={name:"configuration/project-settings.md"};function n(r,e,d,c,g,h){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="project-settings" tabindex="-1"><i class="ph-fill ph-gear-six"></i> Project Settings <a class="header-anchor" href="#project-settings" aria-label="Permalink to &quot;&lt;i class=&quot;ph-fill ph-gear-six&quot;&gt;&lt;/i&gt; Project Settings&quot;">​</a></h1><p>All global WebAP settings are centralized in one location: <strong>Edit -&gt; Project Settings -&gt; Adaptive Performance (Web)</strong></p><p><img src="'+t+'" alt=""></p><h2 id="general-settings" tabindex="-1">General Settings <a class="header-anchor" href="#general-settings" aria-label="Permalink to &quot;General Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Target Min FPS</strong></td><td style="text-align:left;">The performance baseline. • If the current FPS drops below this value (accounting for headroom), the plugin begins reducing graphics quality. • If the FPS remains consistently above it, the plugin attempts to increase quality. <em>Recommendation:</em> Set realistic values. For WebGL, the de-facto standard is <code>60</code>, but for heavy 3D projects, you can utilize <code>30</code>.</td></tr></tbody></table><h2 id="indexer-settings" tabindex="-1">Indexer Settings <a class="header-anchor" href="#indexer-settings" aria-label="Permalink to &quot;Indexer Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Decrease Cooldown</strong></td><td style="text-align:left;">The time (in seconds) the system waits after <em>decreasing</em> quality before evaluating FPS again. <em>Recommendation:</em> Should be short (<code>1.0</code> - <code>2.0</code> sec). The system must react rapidly to lags and &quot;drop ballast&quot; until the FPS stabilizes.</td></tr><tr><td style="text-align:left;"><strong>Increase Cooldown</strong></td><td style="text-align:left;">The wait time after <em>increasing</em> quality. <em>Recommendation:</em> Should be long (<code>5.0</code> - <code>10.0</code> sec). Before burdening the system again, it must verify that the previous graphics upgrade did not destabilize the frame.</td></tr></tbody></table><h2 id="anti-yo-yo-penalty-system" tabindex="-1">Anti Yo-Yo Penalty System <a class="header-anchor" href="#anti-yo-yo-penalty-system" aria-label="Permalink to &quot;Anti Yo-Yo Penalty System&quot;">​</a></h2><p>Protects against &quot;ping-ponging&quot;, where quality endlessly toggles between two levels.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Detection Window</strong></td><td style="text-align:left;">The timeframe during which the system closely monitors FPS after an <em>increase</em> in quality. If an FPS drop occurs within this period, the system classifies it as a Yo-Yo Effect.</td></tr><tr><td style="text-align:left;"><strong>Penalty Lockout Duration</strong></td><td style="text-align:left;">The penalty duration (e.g., <code>60</code> seconds) during which any attempts to <em>increase</em> quality are completely blocked.</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>The penalty exclusively blocks increases. If the FPS drops again, the system can still urgently decrease quality.</p></div><h2 id="scalers" tabindex="-1">Scalers <a class="header-anchor" href="#scalers" aria-label="Permalink to &quot;Scalers&quot;">​</a></h2><p>Every active Scaler possesses a baseline set of parameters. These parameters determine its &quot;cost&quot; to the system. The plugin automatically calculates this cost in real-time: Scalers with the lowest visual impact and matching target (CPU/GPU) are engaged first.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Max Level</strong></td><td style="text-align:left;">The number of discrete steps (levels) between baseline and minimum quality. For example, <code>Max Level = 4</code> means the Scaler possesses 4 degradation steps.</td></tr><tr><td style="text-align:left;"><strong>Min Bound</strong></td><td style="text-align:left;">The minimum scale value (applied when the Scaler reaches its <code>Max Level</code>). For example, <code>0.5</code> represents a quality reduction to 50% of the original.</td></tr><tr><td style="text-align:left;"><strong>Max Bound</strong></td><td style="text-align:left;">The maximum scale value. Typically equals <code>1.0</code> (100% quality), which is the default value at Level 0.</td></tr><tr><td style="text-align:left;"><strong>Visual Impact</strong></td><td style="text-align:left;">The visual impact on the render (<code>Low</code>, <code>Medium</code>, <code>High</code>). The plugin systematically increases levels (reduces quality) on Scalers with a <code>Low</code> impact first.</td></tr><tr><td style="text-align:left;"><strong>Target</strong></td><td style="text-align:left;">Specifies which subsystem the Scaler optimizes (<code>CPU</code>, <code>GPU</code>, or both). If the current system Bottleneck is <code>CPU</code>, the plugin will ignore <code>GPU</code>-Scalers.</td></tr><tr><td style="text-align:left;"><strong>Target Tags</strong></td><td style="text-align:left;">Certain specialized Scalers (<code>WebResolutionScaler</code>, <code>WebCameraClipScaler</code>, <code>WebLayerCullingScaler</code>) apply their settings to specific cameras in the scene rather than globally.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Utilizing Camera Tags</p><p>These Scalers do not utilize the <code>Camera.main</code> call. Instead, they scan active cameras using the <code>Target Tags</code> array.</p><p>By default, the <code>MainCamera</code> tag is specified there. <strong>If your game utilizes custom camera tags (e.g., <code>PlayerCamera</code>), you must add them to the Scaler settings.</strong> Otherwise, scaling for those cameras will fail to trigger.</p></div><h2 id="development-settings" tabindex="-1">Development Settings <a class="header-anchor" href="#development-settings" aria-label="Permalink to &quot;Development Settings&quot;">​</a></h2><p>This section is designated exclusively for debugging plugin behavior within the browser or editor.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Logging</strong></td><td style="text-align:left;">Enables detailed logging of the plugin&#39;s operations to the browser (or Unity) console. Outputs messages regarding Bottleneck shifts, Scaler activations, and Anti Yo-Yo Penalty System triggers.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Optimization</p><p>Logging utilizes the internal <code>DebugWebAP</code> wrapper. It is highly recommended to disable <code>Logging</code> in final release (Production) builds to conserve resources and keep the console clean.</p></div>',19)])])}const y=a(o,[["render",n]]);export{p as __pageData,y as default};
